    feature3Desc: "\u0915\u093f\u0938\u0940 \u092d\u0940 \u092e\u0939\u0924\u094d\u0935\u092a\u0942\u0930\u094d\u0923 \u0924\u093f\u0925\u093f \u0915\u094b \u0915\u092d\u0940 \u0928 \u091a\u0942\u0915\u0947\u0902\u0964",
    feature4Title: "\u092c\u0939\u0941\u092d\u093e\u0937\u0940 \u0938\u0939\u093e\u092f\u0924\u093e",
    feature4Desc: "\u0938\u092d\u0940 \u0915\u0940 \u092e\u0926\u0926 \u0915\u0947 \u0932\u093f\u090f 11 \u092d\u093e\u0937\u093e\u0913\u0902 \u092e\u0947\u0902 \u0909\u092a\u0932\u092c\u094d\u0927\u0964",
    whoWeAreTitle: "\u0939\u092e \u0915\u094c\u0928 \u0939\u0948\u0902",
    whoWeAreContent: "Germany Guide \u090f\u0915 \u092a\u094d\u0930\u0935\u093e\u0938\u0940 \u0926\u094d\u0935\u093e\u0930\u093e \u092c\u0928\u093e\u092f\u093e \u0917\u092f\u093e \u0939\u0948 \u091c\u094b \u0928\u090f \u0926\u0947\u0936 \u092e\u0947\u0902 \u092c\u0938\u0928\u0947 \u0915\u0940 \u091a\u0941\u0928\u094c\u0924\u093f\u092f\u094b\u0902 \u0915\u094b \u0935\u094d\u092f\u0915\u094d\u0924\u093f\u0917\u0924 \u0930\u0942\u092a \u0938\u0947 \u091c\u093e\u0928\u0924\u093e \u0939\u0948\u0964 \u0939\u092e\u093e\u0930\u093e \u0932\u0915\u094d\u0937\u094d\u092f \u0907\u0938 \u092a\u094d\u0930\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u094b \u0938\u092d\u0940 \u0915\u0947 \u0932\u093f\u090f \u0906\u0938\u093e\u0928 \u092c\u0928\u093e\u0928\u093e \u0939\u0948\u0964",
    ctaTitle: "\u0936\u0941\u0930\u0942 \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0924\u0948\u092f\u093e\u0930 \u0939\u0948\u0902?",
    ctaContent: "\u0939\u091c\u093c\u093e\u0930\u094b\u0902 \u0909\u092a\u092f\u094b\u0917\u0915\u0930\u094d\u0924\u093e\u0913\u0902 \u0938\u0947 \u091c\u0941\u0921\u093c\u0947\u0902 \u091c\u094b \u0906\u0924\u094d\u092e\u0935\u093f\u0936\u094d\u0935\u093e\u0938 \u0938\u0947 \u0905\u092a\u0928\u0940 \u091c\u0930\u094d\u092e\u0928\u0940 \u092f\u093e\u0924\u094d\u0930\u093e \u092a\u0930 \u0906\u0917\u0947 \u092c\u0922\u093c \u0930\u0939\u0947 \u0939\u0948\u0902\u0964",
    ctaButton: "\u092e\u0941\u092b\u093c\u094d\u0924 \u092e\u0947\u0902 \u0936\u0941\u0930\u0942 \u0915\u0930\u0947\u0902"
