    guide6Title: "\u091C\u0930\u094D\u092E\u0928\u0940 \u0915\u0947 \u0932\u093F\u090F \u091B\u093E\u0924\u094D\u0930 \u0935\u0940\u091C\u093C\u093E: \u092A\u0942\u0930\u094D\u0923 \u0906\u0935\u0947\u0926\u0928 \u0917\u093E\u0907\u0921 (2025)",
    guide6Desc: "\u091C\u0930\u094D\u092E\u0928 \u091B\u093E\u0924\u094D\u0930 \u0935\u0940\u091C\u093C\u093E \u0915\u0948\u0938\u0947 \u092A\u094D\u0930\u093E\u092A\u094D\u0924 \u0915\u0930\u0947\u0902\u0964 \u0906\u0935\u0936\u094D\u092F\u0915\u0924\u093E\u090F\u0902, \u092C\u094D\u0932\u0949\u0915\u094D\u0921 \u0916\u093E\u0924\u093E, \u0938\u094D\u0935\u093E\u0938\u094D\u0925\u094D\u092F \u092C\u0940\u092E\u093E, \u0935\u093F\u0936\u094D\u0935\u0935\u093F\u0926\u094D\u092F\u093E\u0932\u092F \u092A\u094D\u0930\u0935\u0947\u0936 \u0914\u0930 \u0906\u0935\u0947\u0926\u0928 \u092A\u094D\u0930\u0915\u094D\u0930\u093F\u092F\u093E\u0964",
    guide6Time: "13",
